-- ═══════════════════════════════════════════════════════════════════════════
-- befree-config.sql — Matrice #BeFree editabile (Marca → Connessione → Diametri)
-- ---------------------------------------------------------------------------
-- Sposta l'elenco impianti #BeFree da costante "cotta" nel configuratore a una
-- riga JSON su Supabase, modificabile dall'Admin. Il codice tiene la stessa
-- matrice come default di sicurezza: se questa tabella non risponde, il flusso
-- non si rompe mai (dato medico → mai elenco vuoto lato cliente).
--
-- Permessi di scrittura: admin OPPURE operatori autorizzati singolarmente
-- (profiles.can_edit_befree = true). Il flag lo assegna solo un admin.
--
-- Idempotente. Applicare dal SQL editor del pannello Supabase.
-- Il seed usa ON CONFLICT DO NOTHING: ri-eseguirlo NON sovrascrive le modifiche
-- fatte da interfaccia. Per riseminare da capo: delete from befree_config; poi ri-run.
-- ═══════════════════════════════════════════════════════════════════════════

-- 1) Tabella singleton con tutta la matrice come JSON --------------------------
create table if not exists public.befree_config (
  id          smallint    primary key default 1,
  data        jsonb       not null default '{"marche":[],"impianti":{}}'::jsonb,
  updated_at  timestamptz not null default now(),
  updated_by  uuid        references auth.users(id),
  constraint befree_config_singleton check (id = 1)
);

-- 2) Permesso per-operatore ----------------------------------------------------
alter table public.profiles add column if not exists can_edit_befree boolean not null default false;

-- 3) Estende la guardia anti-escalation (superset di harden-profiles.sql):
--    ruolo / attivo / can_edit_befree li può cambiare SOLO un admin o il service-role.
--    Così un operatore non può auto-assegnarsi can_edit_befree con una PATCH sulla propria riga.
create or replace function public.guard_profiles_privilege()
returns trigger
language plpgsql
security definer
set search_path = public
as $fn$
begin
  if (new.ruolo is distinct from old.ruolo)
     or (new.attivo is distinct from old.attivo)
     or (new.can_edit_befree is distinct from old.can_edit_befree) then
    if not (
      public.is_admin()
      or current_user in ('service_role', 'postgres', 'supabase_admin', 'supabase_auth_admin')
      or coalesce(auth.role(), '') = 'service_role'
    ) then
      raise exception 'Solo un amministratore può cambiare ruolo, stato o permesso #BeFree di un operatore';
    end if;
  end if;
  return new;
end;
$fn$;

drop trigger if exists trg_guard_profiles_privilege on public.profiles;
create trigger trg_guard_profiles_privilege
before update on public.profiles
for each row execute function public.guard_profiles_privilege();

-- 4) Chi può scrivere la matrice #BeFree? --------------------------------------
create or replace function public.puo_modificare_befree()
returns boolean
language sql
stable
security definer
set search_path = public
as $fn$
  select public.is_admin()
      or exists (
        select 1 from public.profiles p
        where p.id = auth.uid()
          and p.can_edit_befree = true
          and coalesce(p.attivo, true) <> false
      );
$fn$;

-- 5) RLS -----------------------------------------------------------------------
alter table public.befree_config enable row level security;

drop policy if exists befree_config_sel on public.befree_config;
create policy befree_config_sel on public.befree_config
  for select using (true);

drop policy if exists befree_config_upd on public.befree_config;
create policy befree_config_upd on public.befree_config
  for update using (public.puo_modificare_befree())
             with check (public.puo_modificare_befree());
-- niente INSERT/DELETE dal client: la riga singola nasce dal seed qui sotto.

grant select, update on public.befree_config to authenticated;

-- 6) Traccia chi/quando modifica + blinda il singleton -------------------------
create or replace function public.befree_config_touch()
returns trigger
language plpgsql
security definer
set search_path = public
as $fn$
begin
  new.id := 1;
  new.updated_at := now();
  new.updated_by := auth.uid();
  return new;
end;
$fn$;

drop trigger if exists befree_config_touch_trg on public.befree_config;
create trigger befree_config_touch_trg
before update on public.befree_config
for each row execute function public.befree_config_touch();

-- 7) Lettura pubblica per il configuratore (anon) ------------------------------
create or replace function public.befree_config_get()
returns jsonb
language sql
stable
security definer
set search_path = public
as $fn$
  select data from public.befree_config where id = 1;
$fn$;
grant execute on function public.befree_config_get() to anon, authenticated;

